(function () {
  'use strict';
  var form = document.getElementById('traceability-search-form');
  if (!form) {
    return;
  }
  var feedback = document.getElementById('traceability-search-feedback');
  var emptyState = document.querySelector('.traceability-result-empty');
  var resultNodes = {
    batch: document.getElementById('traceability-result-batch'),
    farmer: document.getElementById('traceability-result-farmer'),
    location: document.getElementById('traceability-result-location'),
    harvest: document.getElementById('traceability-result-harvest'),
    grade: document.getElementById('traceability-result-grade'),
    port: document.getElementById('traceability-result-port'),
    destination: document.getElementById('traceability-result-destination'),
  };
  var mockBatches = {
    'CCM-2026-001': {
      batch: 'CCM-2026-001',
      farmer: 'FMR-DOU-0182',
      location: 'Meme Division, Southwest Region, Cameroon',
      harvest: '2026-01-18',
      grade: 'Grade 1',
      port: 'Douala Port',
      destination: 'Netherlands',
    },
    'CCM-2026-002': {
      batch: 'CCM-2026-002',
      farmer: 'FMR-SOU-0467',
      location: 'Mvila Division, South Region, Cameroon',
      harvest: '2026-01-26',
      grade: 'Grade 1',
      port: 'Kribi Deep Seaport',
      destination: 'Germany',
    },
    'CCM-2026-003': {
      batch: 'CCM-2026-003',
      farmer: 'FMR-LIT-0329',
      location: 'Nkam Division, Littoral Region, Cameroon',
      harvest: '2026-02-03',
      grade: 'Grade 2',
      port: 'Douala Port',
      destination: 'Belgium',
    },
    'CCM-2026-004': {
      batch: 'CCM-2026-004',
      farmer: 'FMR-EST-0574',
      location: 'Haut-Nyong Division, East Region, Cameroon',
      harvest: '2026-02-14',
      grade: 'Grade 1',
      port: 'Kribi Deep Seaport',
      destination: 'United States',
    },
  };
  function setFeedback(message, isError) {
    if (!feedback) return;
    feedback.textContent = message || '';
    feedback.classList.toggle('is-error', Boolean(isError));
  }
  function setResult(data) {
    resultNodes.batch.textContent = data.batch;
    resultNodes.farmer.textContent = data.farmer;
    resultNodes.location.textContent = data.location;
    resultNodes.harvest.textContent = data.harvest;
    resultNodes.grade.textContent = data.grade;
    resultNodes.port.textContent = data.port;
    resultNodes.destination.textContent = data.destination;
    if (emptyState) {
      emptyState.style.display = 'none';
    }
  }
  function clearResult() {
    resultNodes.batch.textContent = '-';
    resultNodes.farmer.textContent = '-';
    resultNodes.location.textContent = '-';
    resultNodes.harvest.textContent = '-';
    resultNodes.grade.textContent = '-';
    resultNodes.port.textContent = '-';
    resultNodes.destination.textContent = '-';
    if (emptyState) {
      emptyState.style.display = '';
    }
  }
  form.addEventListener('submit', function (event) {
    event.preventDefault();
    var input = form.batchId;
    var batchId = (input && input.value ? input.value : '').trim().toUpperCase();
    if (!batchId) {
      clearResult();
      setFeedback('Please enter a batch ID.', true);
      return;
    }
    var result = mockBatches[batchId];
    if (!result) {
      clearResult();
      setFeedback('No batch found for "' + batchId + '". Try CCM-2026-001 to CCM-2026-004.', true);
      return;
    }
    setResult(result);
    setFeedback('Batch found. Traceability details loaded successfully.', false);
  });
})();
